由KMP算法生成的DFA稀疏且具有我们可以轻松观察到的规律性。一种流行的优化方法不是使用DFA，而是使用较小的＆＃34;部分匹配＆＃34;。表：
 // Knuth–Morris–Pratt算法//复制自http://cprogramming.com/snippets/source-code/knuthmorrispratt-kmp-string-search-algorithmchar * kmp_search（char * haystack，size_t haystack_size，char * needle，size_t needle_size）{int * T; int i，j; char *结果= NULL;如果（needle_size == 0）返回干草堆; / *构造查找表* / T =（int *）malloc（（needle_size + 1）* sizeof（int））; T [0] = -1;对于（i = 0; i＆lt; needle_size; i ++）{T [i + 1] = T [i] + 1;而（T [i + 1]≥0＆amp;针[i]！=针[T [i + 1] -1]）T [i + 1] = T [T [i + 1] -1 ] + 1; } printf（＆＃34;重新启动表：\ n＆＃34;）；对于（i = 0; i＆lt; needle_size + 1; i ++）printf（＆＃34; T [％d] =％d \ n＆＃34 ;, i，T [i]）; / *对（i = j = 0; i <haystack_size;）执行搜索* /（如果（j> = 0）print_compare（干草堆，i，针，j）; if（j＆lt; 0 || haystack [i] == needle [j]）{++ i，++ j;如果（j == needle_size）{结果=干草堆+ i-j;打破; }} else {j = T [j]; if（j ==-1）printf（＆＃34;从头开始重新起针\ n＆＃34;）；否则print_state_needle（needle，j）; }; } free（T）;返回结果；}
  重新启动表：T [0] =-1T [1] = 0T [2] = 1T [3] = 0要进行比较：eex鳗鱼^要进行比较：eex鳗鱼^要进行比较：eex鳗鱼^重新启动针at：鳗鱼^要比较：eex鳗鱼鳗鱼^重新启动针在：eel ^要比较：eex鳗鱼鳗鱼^重新开始的针头要进行比较：eex eel eel ^^重新开始的针头要进行比较：eex鳗鱼鳗鱼^要比较：鳗鱼鳗鱼^要比较：鳗鱼鳗鱼^
